  ('aboriginal-f0899a01-moex-00357', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '有關易服社會勞動的敘述，下列何者錯誤？', '["數罪併罰之數罪均得易服社會勞動且其應執行之刑逾6個月者，亦得易服社會勞動", "社會勞動執行完畢時，所宣告之刑以已執行論", "得易科罰金而未聲請者，得易服社會勞動", "易服社會勞動並非易刑處分"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9d980fdd98d0", "answer_pdf_sha1": "f8fdd9604e08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00358', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '甲犯強盜、偽造文書2罪，分別宣告有期徒刑4年、10月，依刑法第51條定應執行刑時，何者為合法之 應執行刑？', '["8月有期徒刑", "1年6月有期徒刑", "4年2月有期徒刑", "5年6月有期徒刑"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9d980fdd98d0", "answer_pdf_sha1": "f8fdd9604e08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00359', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '關於假釋制度，下列敘述何者正確？', '["受徒刑之執行而有悛悔實據者，無期徒刑逾20年，由監獄報請法務部，得許假釋出獄", "假釋撤銷後，其出獄日數與假釋前已執行之刑期，合併計算為已執行之刑期", "假釋期滿而未經撤銷者，其刑之宣告失其效力", "受徒刑之執行而有悛悔實據者，有期徒刑逾二分之一，由監獄報請法務部，得許假釋出獄"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9d980fdd98d0", "answer_pdf_sha1": "f8fdd9604e08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00360', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '甲法官收受乙被告提供之賄款新臺幣200萬元，而對乙所涉之刑案為違法之無罪判決。有關甲、乙之刑責， 下列敘述何者正確？', '["甲、乙成立公務員違背職務受賄罪之共同正犯", "甲、乙成立公務員圖利罪之共同正犯", "甲成立公務員違背職務受賄罪，乙成立公務員違背職務行賄罪", "甲成立枉法裁判罪，乙不成立犯罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9d980fdd98d0", "answer_pdf_sha1": "f8fdd9604e08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00361', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '下列何者不是公務員收受賄賂罪所稱之職務上行為？', '["法官甲從事審判", "建設局長甲指揮下屬乙核發建造執照", "檢察官甲收取出版社之報酬撰寫小說與書評", "司法警察官甲查緝犯罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9d980fdd98d0", "answer_pdf_sha1": "f8fdd9604e08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00362', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '下列何種行為，不構成刑法第199條之預備偽造貨幣罪？', '["意圖供偽造之用，而製造各項器械原料者", "意圖供偽造之用，而收受各項器械原料者", "意圖供偽造之用，而交付各項器械原料者", "意圖供偽造之用，而期約各項器械原料者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9d980fdd98d0", "answer_pdf_sha1": "f8fdd9604e08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00363', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '甲駕車闖紅燈，不慎撞及行經斑馬線之路人乙，乙當場死亡，甲隨後逃逸無縱。甲之刑事責任為何？', '["甲成立過失致死罪與肇事逃逸罪，兩罪數罪併罰", "甲成立過失致死罪與有義務遺棄罪，兩罪數罪併罰", "甲成立過失致死罪與肇事逃逸罪，兩罪想像競合", "甲成立過失致死罪與有義務遺棄罪，兩罪想像競合"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9d980fdd98d0", "answer_pdf_sha1": "f8fdd9604e08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00364', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '甲為警察局的約僱清潔人員，偶然聽聞警察談及乙之前科資料，乃將之洩漏予媒體記者丙。下列敘述何者 正確？', '["甲與丙共同犯洩漏國防以外秘密罪", "甲犯洩漏國防以外秘密罪", "甲不構成洩漏國防以外秘密罪", "甲犯妨害書信秘密罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9d980fdd98d0", "answer_pdf_sha1": "f8fdd9604e08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00365', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '老師甲告知學生乙，如果上課再打瞌睡，就要將其當掉。甲之行為應如何論罪？', '["恐嚇危害安全罪", "強制罪", "恐嚇取財罪", "不成立犯罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9d980fdd98d0", "answer_pdf_sha1": "f8fdd9604e08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
